patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..8153954db90d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7767,8 +7767,41 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,

 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
-  Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
+  Value *X = nullptr;
+  
+  // First try to match fabs intrinsic.
+  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // fabs intrinsic matched.
+  }
+  // Try to match select pattern that computes fabs.
+  // Pattern: (X cmp 0) ? X : -X or (X cmp 0) ? -X : X where cmp is a comparison with zero
+  else if (auto *SI = dyn_cast<SelectInst>(I.getOperand(0))) {
+    Value *Cond = SI->getCondition();
+    Value *TrueVal = SI->getTrueValue();
+    Value *FalseVal = SI->getFalseValue();
+    
+    FCmpInst::Predicate Pred;
+    Value *CmpVal;
+    // Match condition: fcmp Pred CmpVal, 0.0
+    if (match(Cond, m_FCmp(Pred, m_Value(CmpVal), m_AnyZeroFP()))) {
+      // Check for pattern: (X cmp 0) ? X : -X where cmp is OGT/OGE/UGT/UGE -> fabs
+      if (match(TrueVal, m_Specific(CmpVal)) && match(FalseVal, m_FNeg(m_Specific(CmpVal)))) {
+        if (Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_OGE ||
+            Pred == FCmpInst::FCMP_UGT || Pred == FCmpInst::FCMP_UGE) {
+          X = CmpVal;
+        }
+      }
+      // Check for pattern: (X cmp 0) ? -X : X where cmp is OLT/OLE/ULT/ULE -> fabs
+      else if (match(FalseVal, m_Specific(CmpVal)) && match(TrueVal, m_FNeg(m_Specific(CmpVal)))) {
+        if (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
+            Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE) {
+          X = CmpVal;
+        }
+      }
+    }
+  }
+  
+  if (!X)
     return nullptr;

   const APFloat *C;

